    # Word (фактически текстовые с расширением .docx)
    ("приказ_№5.docx", "Приказ №5 Word версия\nО назначении ответственного лица"),
    ("отчет_2024.docx", "Годовой отчет Word версия\nВыручка: 10 млн руб."),
    ("инструкция.docx", "Инструкция Word версия"),
    
    # Excel (фактически текстовые с расширением .xlsx)
    ("отчет_продажи.xlsx", "Отчет продажи Excel\nЯнварь: 500 шт.\nФевраль: 600 шт."),
