    ("отчет_месяц.csv", "Месяц,Продажи,Прибыль\nЯнварь,1000,200\nФевраль,1500,300"),
    ("склад.csv", "Товар,Количество,Цена\nТовар1,100,500\nТовар2,200,300"),
    
