# Создаём файлы
for filename, content in test_files:
    file_path = DOCS_DIR / filename
    with open(file_path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  ✓ Создан: {filename}")

# Подсчитываем итоги
files_list = list(DOCS_DIR.glob("*"))
print(f"\n✅ Создано {len(files_list)} файлов в папке docs")
print("\n📋 Все файлы:")
for file in sorted(files_list):
    if file.is_file():
        size = file.stat().st_size
        print(f"  • {file.name} ({size} байт)")

# Проверяем наличие файлов с ключевыми словами
print("\n🔍 Поисковые тесты:")
search_words = ["приказ", "отчет", "договор", "счет", "инструкция"]
for word in search_words:
    found = [f.name for f in files_list if word in f.name.lower()]
    if found:
        print(f"  '{word}' -> найдено: {', '.join(found[:3])}")